package main

import (
	"fmt"
	"reflect"
)

func main() {
	inner := fmt.Errorf("inner error")
	wrapped := fmt.Errorf("wrapped: %w", inner)

	t := reflect.TypeOf(wrapped)
	fmt.Printf("Type: %s\n", t.String())
	fmt.Printf("PkgPath: %s\n", t.PkgPath())
	fmt.Printf("Name: %s\n", t.Name())

	// Check if it implements Unwrap
	if u, ok := wrapped.(interface{ Unwrap() []error }); ok {
		errs := u.Unwrap()
		for _, e := range errs {
			fmt.Printf("Unwrapped: %v (type: %s)\n", e, reflect.TypeOf(e).String())
		}
	}
}
EOF
