package main

import (
	"errors"
	"fmt"
	"reflect"
)

func main() {
	inner := fmt.Errorf("inner error")
	single := fmt.Errorf("wrapped: %w", inner)
	joined := errors.Join(inner, fmt.Errorf("another"))

	// Check single wrap
	t1 := reflect.TypeOf(single)
	fmt.Printf("single Type: %s, Name: '%s', PkgPath: '%s'\n", t1.String(), t1.Name(), t1.PkgPath())

