		fmt.Printf("single.Unwrap: %v (type: %s)\n", u, reflect.TypeOf(u).String())
	}
	if u := errors.Unwrap(joined); u != nil {
		fmt.Printf("joined.Unwrap: %v (type: %s)\n", u, reflect.TypeOf(u).String())
	}
}
GOEOF
