package main

import (
	"errors"
	"fmt"
	"reflect"

	"go.opentelemetry.io/otel/semconv/v1.40.0"
)

func main() {
	// Case 1: bare errors.New
	err1 := errors.New("something broke")
	kv1 := semconv.ErrorType(err1)
	fmt.Printf("errors.New: %s\n", kv1.Value.AsString())

	// Case 2: wrapped with fmt.Errorf
	err2 := fmt.Errorf("wrapped: %w", errors.New("inner error"))
	kv2 := semconv.ErrorType(err2)
	fmt.Printf("fmt.Errorf(wrapped): %s  (type: %s)\n", kv2.Value.AsString(), reflect.TypeOf(err2).String())

	// Case 3: custom error type with ErrorType method, wrapped in fmt.Errorf
	type myErr struct{ code int }
	myErrImpl := &myErr{code: 500}
	// myErr doesn't implement ErrorType
	err3 := fmt.Errorf("wrapped: %w", myErrImpl)
	kv3 := semconv.ErrorType(err3)
	fmt.Printf("fmt.Errorf(myErr): %s  (type: %s)\n", kv3.Value.AsString(), reflect.TypeOf(err3).String())
	fmt.Printf("  inner type: %s\n", reflect.TypeOf(myErrImpl).String())

	// Case 4: errors.Join
	err4 := errors.Join(errors.New("a"), errors.New("b"))
	kv4 := semconv.ErrorType(err4)
	fmt.Printf("errors.Join: %s  (type: %s)\n", kv4.Value.AsString(), reflect.TypeOf(err4).String())
}
GOEOF
