package main

import (
	"errors"
	"fmt"
	"reflect"

	"go.opentelemetry.io/otel/semconv/v1.40.0"
)

type myErr struct{ code int }

func (e *myErr) Error() string { return fmt.Sprintf("myErr(%d)", e.code) }

func main() {
	// Case 1: bare errors.New
	err1 := errors.New("something broke")
	kv1 := semconv.ErrorType(err1)
	fmt.Printf("errors.New: %s\n", kv1.Value.AsString())

	// Case 2: wrapped with fmt.Errorf
	err2 := fmt.Errorf("wrapped: %w", errors.New("inner error"))
	kv2 := semconv.ErrorType(err2)
	fmt.Printf("fmt.Errorf(wrapped): %s  (type: %s)\n", kv2.Value.AsString(), reflect.TypeOf(err2).String())

