func typeStr(i any) string {
	t := reflect.TypeOf(i)
	for t.Name() == "" {
		// Unwrap the error to find the first non-wrapper type.
		switch e := i.(type) {
		case interface{ Unwrap() []error }:
			errs := e.Unwrap()
			if len(errs) > 0 {
				i = errs[0]
				t = reflect.TypeOf(i)
				continue
			}
		case interface{ Unwrap() error }:
			if u := e.Unwrap(); u != nil {
				i = u
				t = reflect.TypeOf(i)
				continue
			}
		}
		break
	}

	if t.PkgPath() == "" && t.Name() == "" {
		// Likely a builtin type.
		return t.String()
	}
	return fmt.Sprintf("%s.%s", t.PkgPath(), t.Name())
}

